import {SMSType, client, FieldType} from '~/utils/type'
import CountDown from '~/components/public/countDown';
import Cookies from 'js-cookie'
import { mapActions } from "vuex";
import config from '~/config'
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
       link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
 layout: "user_lauout",
 components: {
   CountDown
 },
 async asyncData({$get, $post}) {
   let avatar = "";
   let nickName = "";
   let mobile = "";
   let sex = 0;
   let radio = 0
   let createTime = '';
   let sn = '';
   let res = await $get("user/info");
   if(res.code == 1) {
     avatar = res.data.avatar;
     nickName = res.data.nickname;
     mobile = res.data.mobile;
     sex = res.data.sex;
     radio = sex;
     createTime = res.data.create_time;
     sn = res.data.sn
   }
   return {
     avatar,
     nickName,
     mobile,
     sex,
     radio,
     createTime,
     sn
   }
 },
 data() {
   return {
     action: config.baseUrl + 'file/formimage',
     nickName: '',
     radio: 1,
     showChangeNumber: false,
     showPwdPop: false,
     telephone: '',
     verifyCode: '',
     pwd: '',
     againPwd: '',
     smsType: SMSType.CHANGE_MOBILE,
     canSendNumber: true,
     canSendPwd: true,
     fileList: []
   }
 },
 methods: {
   ...mapActions(['getPublicData']),
    async saveUserInfo() {
      let res = await this.$post("pc/changeUserInfo", {
        sex: this.radio,
        nickname: this.nickName
      });
      if(res.code == 1) {
        this.$message({
          message: res.msg,
          type: 'success'
        });
        this.getPublicData()
      }
    },
    closeChangeNumber() {
      this.telephone = '';
      this.verifyCode = '';
      this.showChangeNumber = false;
    },
    closePwdPop() {
      this.telephone = '';
      this.verifyCode = '';
      this.showPwdPop = false;
    },
    openChangeNumber() {
        this.showChangeNumber = true;
        this.smsType = this.mobile ? SMSType.CHANGE_MOBILE : SMSType.BIND;
    },
    openChangePwdPop() {
      this.showPwdPop = true;
      this.smsType = SMSType.FINDPWD;
    },
    async sndSmsToPhone() {
      if((this.smsType == SMSType.CHANGE_MOBILE || this.smsType == SMSType.BIND) && !this.canSendNumber) {
        return;
      }
      else if(this.smsType == SMSType.FINDPWD && !this.canSendPwd) {
        return;
      }
      if(this.smsType == SMSType.CHANGE_MOBILE && !this.telephone) {
        this.$message({
          message: '请输入手机号',
          type: 'error'
        })
        return;
      }

      let res = await this.$post("sms/send", {
          mobile: this.smsType == SMSType.FINDPWD ? this.mobile : this.telephone,
          key: this.smsType
      });
      if(res.code == 1) {
        this.smsType == SMSType.CHANGE_MOBILE ? this.canSendNumber = false : this.canSendPwd = false;
        this.$message({
          message: '发送成功',
          type: 'success'
        })
      }
    },
    async changeUserMobile() {
      if (!this.telephone) {
        this.$message({
          message: '请输入新的手机号码',
          type: 'error'
        })
        return;
      }
      if (!this.verifyCode) {
        this.$message({
          message: '请输入验证码',
          type: 'error'
        })
        return;
      }
      let res = await this.$post("user/changeMobile", {
        mobile: this.mobile,
        new_mobile: this.telephone,
        code: this.verifyCode,
        action: this.mobile ? 'change' : '',
        client: client
      });
      if(res.code == 1) {
        this.showChangeNumber = false;
        this.$message.success(res.msg);
        this.getPublicData();
      }
    },
    async setPassWord() {
      if(!this.verifyCode) {
        this.$message({
          message: '请输入验证码',
          type: 'error'
        })
        return;
      }
      if(!this.pwd) {
        this.$message({
          message: '请输入密码',
          type: 'error'
        })
        return;
      }
      if(!this.againPwd) {
        this.$message({
          message: '请输入确认密码',
          type: 'error'
        })
        return
      }
      if(this.pwd != this.againPwd) {
        this.$message({
          message: '两次密码输入不一致',
          type: 'error'
        })
        return;
      }
      let res = await this.$post("login_password/forget", {
        mobile: this.mobile,
        code: this.verifyCode,
        password: this.pwd,
        repassword: this.againPwd,
        client: client
      })
      if(res.code == 1) {
        this.$message({
          message: res.msg,
          type: 'success'
        });
        this.showPwdPop = false;
        const token = res.data.token
        Cookies.set('token', token, { expires: 60 });
      }
    },
    async uploadFileSuccess(res, fileList) {
      let respond = await this.$post('user/setInfo', {
        field: FieldType.AVATAR,
        value: res.data.base_url
      });
      if(respond.code == 1) {
        this.$message({
          message: respond.msg,
          type: 'success'
        })
        let userRes = await this.$get("user/info")
        if(userRes.code == 1) {
          this.avatar = userRes.data.avatar;
          this.nickName = userRes.data.nickname;
          this.mobile = userRes.data.mobile;
          this.sex = userRes.data.sex;
          this.radio = this.sex;
          this.createTime = userRes.data.create_time;
        }
      }
    },
 }
}
